#!/usr/bin/env python3
"""Apply v0.12.6.1 clean handoff staging/scope hotfix."""
from pathlib import Path

FILES = {
    "tools/create_source_run_beta_staging.py": '#!/usr/bin/env python3\n"""Create a clean source-run beta staging folder for The Dragon\'s Touch.\n\nThis helper copies only active source-run handoff files/folders into a clean\nstaging directory so package verification does not scan historical development\narchives such as Retired UI, Old Do Not Use, exe tests, dist, or build.\n\nNo network calls. No app launch. No analysis run.\n"""\nfrom __future__ import annotations\n\nimport argparse\nimport shutil\nfrom pathlib import Path\n\nREQUIRED_FILES = [\n    "requirements.txt",\n    "README_START_HERE.txt",\n    "README.md",\n    "desktop_ui_launcher.py",\n    "main.py",\n    "config.py",\n]\n\nACTIVE_FOLDERS = [\n    "ui",\n    "combo_awareness",\n    "analysis",\n    "app_io",\n    "cuts",\n    "data",\n    "io",\n    "legality",\n    "parsing",\n    "replacements",\n    "reports",\n    "rules",\n    "Decklists",\n    "collection",\n    "Outputs",\n    "settings",\n    "tools",\n    "docs",\n]\n\nFORBIDDEN_DIR_NAMES = {\n    "__pycache__",\n    "dist",\n    "build",\n    "build_specs",\n    "_internal",\n    ".git",\n    ".mypy_cache",\n    ".pytest_cache",\n    ".ruff_cache",\n    ".venv",\n    "venv",\n    "env",\n}\n\nFORBIDDEN_TOP_LEVEL_NAMES = {\n    "Retired UI",\n    "Old Do Not Use",\n    "Old do not use",\n    "Old Do not use",\n    "Old",\n    "MockUP",\n    "Mockups",\n    "Mockups Do Not Use",\n    "exe tests",\n    "EXE tests",\n    "Files outside",\n}\n\nFORBIDDEN_SUFFIXES = {".pyc", ".pyo", ".exe", ".bat"}\nKNOWN_HUGE_DATA_FILES = {\n    "data/scryfall_cards.json",\n    "data/combo.json",\n    "data/commander_spellbook/combo_index.json",\n    "data/commander_spellbook/combo_index_parity.json",\n}\n\n\ndef rel_posix(path: Path, root: Path) -> str:\n    return path.relative_to(root).as_posix()\n\n\ndef should_skip(path: Path, source_root: Path) -> tuple[bool, str]:\n    rel = rel_posix(path, source_root)\n    parts = path.relative_to(source_root).parts\n\n    if parts and parts[0] in FORBIDDEN_TOP_LEVEL_NAMES:\n        return True, f"archived top-level folder: {parts[0]}"\n    if any(part in FORBIDDEN_DIR_NAMES for part in parts):\n        return True, "cache/build/internal folder"\n    if any("mockup" in part.lower() for part in parts):\n        return True, "MockUP/old handoff item"\n    if path.is_file() and path.suffix.lower() in FORBIDDEN_SUFFIXES:\n        return True, f"forbidden file type: {path.suffix}"\n    if rel in KNOWN_HUGE_DATA_FILES:\n        return True, "generated/downloaded data rebuilt by tester"\n    return False, ""\n\n\ndef copy_tree_filtered(src: Path, dst: Path, source_root: Path) -> tuple[int, int]:\n    copied = 0\n    skipped = 0\n    if not src.exists():\n        dst.mkdir(parents=True, exist_ok=True)\n        return copied, skipped\n\n    for item in src.rglob("*"):\n        skip, _reason = should_skip(item, source_root)\n        if skip:\n            skipped += 1\n            continue\n        rel = item.relative_to(src)\n        target = dst / rel\n        if item.is_dir():\n            target.mkdir(parents=True, exist_ok=True)\n        elif item.is_file():\n            target.parent.mkdir(parents=True, exist_ok=True)\n            shutil.copy2(item, target)\n            copied += 1\n    dst.mkdir(parents=True, exist_ok=True)\n    return copied, skipped\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser(description="Create a clean source-run beta staging folder.")\n    parser.add_argument("--source", default=".", help="Project root to copy from. Default: current folder.")\n    parser.add_argument(\n        "--dest",\n        default="_handoff_staging/The Dragon\'s Touch v0.12 Source-Run Beta",\n        help="Destination staging folder. Default: _handoff_staging/The Dragon\'s Touch v0.12 Source-Run Beta",\n    )\n    parser.add_argument("--overwrite", action="store_true", help="Replace the destination if it already exists.")\n    args = parser.parse_args()\n\n    source_root = Path(args.source).resolve()\n    dest_root = Path(args.dest)\n    if not dest_root.is_absolute():\n        dest_root = (source_root / dest_root).resolve()\n\n    print("The Dragon\'s Touch — Clean Source-Run Beta Staging Helper")\n    print("=========================================================")\n    print(f"Source:      {source_root}")\n    print(f"Destination: {dest_root}")\n\n    if not source_root.exists():\n        print("FAIL — Source folder does not exist.")\n        return 1\n\n    if dest_root.exists():\n        if not args.overwrite:\n            print("FAIL — Destination already exists.")\n            print("Run again with --overwrite if you want to replace only the staging folder.")\n            return 1\n        try:\n            dest_root.relative_to(source_root / "_handoff_staging")\n        except ValueError:\n            print("FAIL — Refusing to overwrite a destination outside _handoff_staging.")\n            return 1\n        shutil.rmtree(dest_root)\n\n    dest_root.mkdir(parents=True, exist_ok=True)\n\n    blockers = 0\n    copied_files = 0\n    skipped_items = 0\n\n    for filename in REQUIRED_FILES:\n        src = source_root / filename\n        dst = dest_root / filename\n        if src.exists() and src.is_file():\n            shutil.copy2(src, dst)\n            copied_files += 1\n            print(f"PASS — Copied {filename}")\n        else:\n            blockers += 1\n            print(f"FAIL — Required file missing: {filename}")\n\n    for folder in ACTIVE_FOLDERS:\n        src = source_root / folder\n        dst = dest_root / folder\n        c, s = copy_tree_filtered(src, dst, source_root)\n        copied_files += c\n        skipped_items += s\n        if src.exists():\n            print(f"PASS — Copied active folder: {folder} ({c} file(s), {s} skipped item(s))")\n        else:\n            print(f"WARN — Active folder not found, created empty folder: {folder}")\n\n    print()\n    print("Result")\n    print("------")\n    if blockers:\n        print(f"RESULT — FAIL ({blockers} blocker issue(s))")\n        return 1\n\n    print(f"RESULT — PASS — Clean staging folder created with {copied_files} copied file(s).")\n    print()\n    print("Next commands:")\n    print(f"cd \\"{dest_root}\\"")\n    print("py tools\\\\verify_source_run_beta_package.py")\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n',
    "tools/verify_source_run_beta_package.py": '#!/usr/bin/env python3\n"""Clean source-run beta package verifier for The Dragon\'s Touch.\n\nRun this from the clean handoff/staging folder, not from the full development\narchive root. If you keep historical folders, first run:\n\n    py tools\\create_source_run_beta_staging.py --overwrite\n\nThen cd into the staging folder and run this verifier there.\n"""\nfrom __future__ import annotations\n\nimport argparse\nfrom pathlib import Path\n\nREQUIRED_FILES = [\n    "requirements.txt",\n    "README_START_HERE.txt",\n    "README.md",\n    "desktop_ui_launcher.py",\n    "main.py",\n    "config.py",\n]\n\nREQUIRED_FOLDERS = [\n    "ui",\n    "combo_awareness",\n    "analysis",\n    "app_io",\n    "cuts",\n    "data",\n    "io",\n    "legality",\n    "parsing",\n    "replacements",\n    "reports",\n    "rules",\n    "Decklists",\n    "collection",\n    "Outputs",\n    "settings",\n    "tools",\n]\n\nREQUIRED_TOOLS = [\n    "tools/data_setup.py",\n    "tools/build_combo_index.py",\n    "tools/download_commander_spellbook_bulk_json.py",\n    "tools/check_source_run_environment.py",\n]\n\nFORBIDDEN_DIR_NAMES = {\n    "__pycache__",\n    "dist",\n    "build",\n    "build_specs",\n    "_internal",\n}\n\nFORBIDDEN_TOP_LEVEL_NAMES = {\n    "Retired UI",\n    "Old Do Not Use",\n    "Old do not use",\n    "Old Do not use",\n    "MockUP",\n    "Mockups",\n    "exe tests",\n    "EXE tests",\n    "Files outside",\n}\n\nFORBIDDEN_SUFFIXES = {".pyc", ".pyo", ".exe", ".bat"}\nKNOWN_HUGE_DATA_FILES = {\n    "data/scryfall_cards.json",\n    "data/combo.json",\n    "data/commander_spellbook/combo_index.json",\n    "data/commander_spellbook/combo_index_parity.json",\n}\nLARGE_FILE_WARN_BYTES = 100 * 1024 * 1024\n\n\ndef rel_posix(path: Path, root: Path) -> str:\n    return path.relative_to(root).as_posix()\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser(description="Verify a clean source-run beta handoff package.")\n    parser.add_argument("--root", default=".", help="Package root to verify. Default: current folder.")\n    args = parser.parse_args()\n\n    root = Path(args.root).resolve()\n    blockers: list[str] = []\n    warnings: list[str] = []\n\n    print("The Dragon\'s Touch — Source-Run Beta Package Verifier")\n    print("=====================================================")\n    print(f"Package root: {root}")\n    print()\n\n    if not root.exists():\n        print("RESULT — FAIL")\n        print("Package root does not exist.")\n        return 1\n\n    print("Required files")\n    print("--------------")\n    for rel in REQUIRED_FILES:\n        path = root / rel\n        if path.is_file():\n            print(f"PASS — Required file found: {rel}")\n        else:\n            msg = f"Required file missing: {rel}"\n            blockers.append(msg)\n            print(f"FAIL — {msg}")\n\n    print()\n    print("Required folders")\n    print("----------------")\n    for rel in REQUIRED_FOLDERS:\n        path = root / rel\n        if path.is_dir():\n            print(f"PASS — Required folder found: {rel}/")\n        else:\n            msg = f"Required folder missing: {rel}/"\n            blockers.append(msg)\n            print(f"FAIL — {msg}")\n\n    print()\n    print("Required tools")\n    print("--------------")\n    for rel in REQUIRED_TOOLS:\n        path = root / rel\n        if path.is_file():\n            print(f"PASS — Required tool found: {rel}")\n        else:\n            msg = f"Required tool missing: {rel}"\n            blockers.append(msg)\n            print(f"FAIL — {msg}")\n\n    print()\n    print("Forbidden handoff artifacts")\n    print("---------------------------")\n    forbidden_count = 0\n    for item in root.rglob("*"):\n        rel = rel_posix(item, root)\n        parts = item.relative_to(root).parts\n\n        if parts and parts[0] in FORBIDDEN_TOP_LEVEL_NAMES:\n            msg = f"Forbidden archived/development folder found in package: {parts[0]}/"\n            if msg not in blockers:\n                blockers.append(msg)\n                print(f"FAIL — {msg}")\n                forbidden_count += 1\n            continue\n\n        if item.is_dir() and item.name in FORBIDDEN_DIR_NAMES:\n            msg = f"Forbidden folder found: {rel}/"\n            blockers.append(msg)\n            print(f"FAIL — {msg}")\n            forbidden_count += 1\n            continue\n\n        if any("mockup" in part.lower() for part in parts):\n            msg = f"Forbidden MockUP/old handoff style file or folder found: {rel}"\n            blockers.append(msg)\n            print(f"FAIL — {msg}")\n            forbidden_count += 1\n            continue\n\n        if item.is_file():\n            if item.suffix.lower() in FORBIDDEN_SUFFIXES:\n                msg = f"Forbidden file type found: {rel}"\n                blockers.append(msg)\n                print(f"FAIL — {msg}")\n                forbidden_count += 1\n            if rel in KNOWN_HUGE_DATA_FILES:\n                msg = f"Huge generated data file should not be bundled in clean source-run handoff: {rel}"\n                blockers.append(msg)\n                print(f"FAIL — {msg}")\n                forbidden_count += 1\n            elif item.stat().st_size >= LARGE_FILE_WARN_BYTES:\n                size_mb = item.stat().st_size / (1024 * 1024)\n                msg = f"Large file found; confirm it belongs in the handoff: {rel} ({size_mb:.1f} MB)"\n                warnings.append(msg)\n                print(f"WARN — {msg}")\n\n    if forbidden_count == 0:\n        print("PASS — No forbidden handoff artifacts found")\n\n    print()\n    print("Expected absences")\n    print("-----------------")\n    for rel in sorted(KNOWN_HUGE_DATA_FILES):\n        if not (root / rel).exists():\n            print(f"PASS — Expected generated data is absent: {rel}")\n\n    print()\n    print("Result")\n    print("------")\n    if blockers:\n        print(f"RESULT — FAIL ({len(blockers)} blocker issue(s), {len(warnings)} warning(s))")\n        print("Fix blocker items before creating a beta handoff ZIP.")\n        print()\n        print("If these blockers are only from historical folders, run:")\n        print("py tools\\\\create_source_run_beta_staging.py --overwrite")\n        print("Then cd into the staging folder and run this verifier again.")\n        return 1\n\n    if warnings:\n        print(f"RESULT — PASS WITH WARNINGS ({len(warnings)} warning(s))")\n        print("Review warnings before handoff.")\n        return 0\n\n    print("RESULT — PASS")\n    print("Clean source-run beta handoff package is ready for ZIP creation.")\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n',
}


def main() -> int:
    print("v0.12.6.1 — Clean Handoff Staging / Verifier Scope Hotfix")
    print("=========================================================")
    for rel, content in FILES.items():
        path = Path(rel)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8", newline="\n")
        print(f"PASS — Wrote {rel}")
    print()
    print("PASS — Hotfix applied")
    print()
    print("Next commands:")
    print("py tools\\verify_v0.12.6.1_clean_handoff_staging_scope_hotfix.py")
    print("py tools\\create_source_run_beta_staging.py --overwrite")
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
